	.TITLE	ZMIDI	.PROC	Z80; Switch pour assemblage; ----------------------EPROM	=	0; Memory areas; ------------	.IF	EPROMROMM	=	O'0IVTAB	=	ROMM+O'10RAMM	=	O'44000STACK	=	O'47777	.ELSEROMM	=	O'40100IVTAB	=	ROMM+O'10RAMM	=	O'44000STACK	=	O'47777	.ENDIF; Constantes MIDI; ---------------ENDATT	=	H'7EENDREL	=	H'7F; Table pour un gnrateur; ------------------------	.LOC	0OETAT:	.BLKB	1		; 0=libre, 1=presse, 2=relche, 3=inexistantOSEL:	.BLKB	1		; carte concerneONOTE:	.BLKB	1		; note joue (-1 si libre)OAMPL:	.BLKB	1		; amplitudeOTIME:	.BLKB	2		; tempsOPENV:	.BLKB	2		; ^enveloppeLG:; Variables; ---------	.LOC	RAMMFIFO:	.BLKB	256		; fifo (buffer circulaire)HEAD:	.BLKB	2		; ^tte dans le fifoTAIL:	.BLKB	2		; ^queue dans le fifoCANAL:	.BLKB	1		; canal MIDI selon switchs (0..15)CARTE:	.BLKB	1		; cartes prsentesTAUSE:	.BLKB	8*LG		; table des gnrateurs utilissNPAT0:	.BLKB	1		; numro patterne d'attaqueNPAT1:	.BLKB	1		; numro patterne intermdiaireNPAT2:	.BLKB	1		; numro patterne de releaseTEMP01:	.BLKB	1		; temps de 0 --> 1TEMP12:	.BLKB	1		; temps de 1 --> 2; Divers; ------TRAP	=	O'367		; retour au debug matreFLGON	=	O'377FLGOFF	=	O'000; SIO address; -----------SIO	=	O'300		; SIO Base add.SIAD	=	SIO		; Ch. A DataSIBD	=	SIAD+1		; Ch. B DataSIAC	=	SIBD+1		; Ch. A ControlSIBC	=	SIAC+1  	; Ch. B Control; PIO  address; ------------PIO	=	O'314PIAD	=	PIO+0		; PIO 1 A dataPIAC	=	PIO+2		; PIO 1 A commandPIBD	=	PIO+1		; PIO 1 B dataPIBC	=	PIO+3		; PIO 1 B command; PIO carte per; -------------PPIO	=	O'310PPIAD	=	PPIO+0		; PPIO 1 A dataPPIAC	=	PPIO+2		; PPIO 1 A commandPPIBD	=	PPIO+1		; PPIO 1 B dataPPIBC	=	PPIO+3		; PPIO 1 B command; Noms logiques; -------------SELECT	=	PIAD		; slection des cartes (out)DATA	=	PIBD		; donnes (out)CONTROL	=	PPIAD		; contrle (in) BSWI0	=	0		;  switch 0 BSWI1	=	1		;  switch 1 BSWI2	=	2		;  switch 2 BSWI3	=	3		;  switch 3 BSWI4	=	4		;  switch 4 BSWI5	=	5		;  switch 5 BJSL	=	6		;  je suis l BRDY	=	7		;  readyLED	=	PPIBD		; 8 leds (out); CTC address; -----------CTC	=	O'304CTC0	=	CTC+0		; CTC channel 0CTC1	=	CTC+1		; CTC channel 1CTC2	=	CTC+2		; CTC channel 2CTC3	=	CTC+3		; CTC channel 3; PIO definition; --------------PINPMD	=	O'117		; Input modePOUTMD	=	O'017		; Output modePBIDMD	=	O'217		; Bidirectional modePCTRMD	=	O'317		; Control modePINTEN	=	O'207		; Interrupt enablePINTDS	=	O'007		; Interrupt disablePAND	=	O'107		; AND functionPOR	=	O'007		; OR functionPHIGH	=	O'047		; Active highPLOW	=	O'007		; Active lowPMFOL	=	O'027		; Mask followPRPINT	=	O'027		; Reset pending int.; CTC definition; --------------CINTDS	=	O'001		; Interrupt disableCINTEN	=	O'201		; Interrupt enableCNTMD	=	O'101		; Counter modeCTMD	=	O'001		; Timer modeCP256	=	O'041		; Prescaler factor = O'256CP016	=	O'001		; Prescaler factor = O'16CPSLP	=	O'021		; Positive edgeCNSLP	=	O'001		; Negative edgeCEXTR	=	O'011		; External triggerCNXTR	=	O'001		; No external triggerCLDCS	=	O'005		; Load time constantCRSET	=	O'003		; Reset; SIO definition; --------------; write register 0R0	=	O'0RSEXI	=	O'20		; Reset external interruptsRSCHL	=	O'30		; Reset channelRSRCVI	=	O'40		; Reset receiver interruptsRSTBMT	=	O'50		; Reset xmit buffer empty int.RSEROR	=	O'60		; Reset errorRETIA	=	O'70		; Return from int. (ch. a only); write register 1 (interrupt control)R1	=	O'1EXTIE	=	O'1		; Ext int. enable (dcd,cts)TRSIE	=	O'2		; Xmit interrupt enableSTAVEC	=	O'4		; Status afects vectorRIDIS	=	O'0		; Rcv. interrupt disableRCVIM1	=	O'10		; Int. on first char.RCVIM2	=	O'20		; All char. int (with par. aff. vec)RCVIM3	=	O'30		;  "   "     " (without "   "    " ); write register 2 loaded only into channel BR2	=	O'2; write register 3 (xrcv mode only)R3	=	O'3RX5B	=	O'0		; 5 bits/char.RX6B	=	O'200		; 6 bits/char.RX7B	=	O'100		; 7 bits/char.RX8B	=	O'300		; 8 bits/char.AUTEN	=	O'40		; Enable control of dcd and ctsRCVEN	=	O'1		; Receiver enable; write register 4 (xmit/xrcv mode)R4	=	O'4X1	=	O'0		; Divide clock by 1X16	=	O'100		;    "     "   "  16X32	=	O'200		;    "     "   "  32X64	=	O'300		;    "     "    " 64SB1	=	O'4		; Number of stop bits 1SB15	=	O'10		;   "    "    "   "   1.5SB2	=	O'14		;   "    "    "   "   2SYNCMD	=	O'0		; Synchronous modePAREN	=	O'1		; Parity enablePEVEN	=	O'2		; Parity even; write register 5 (xmit mode only)R5	=	O'5TX5B	=	O'0		; 5 bits/char.TX6B	=	O'100		; 6 bits/char.TX7B	=	O'40		; 7 bits/char.TX8B	=	O'140		; 8 bits/char.RTS	=	O'2		; RTS controlTRSEN	=	O'10		; Transmitter enableDTR	=	O'200		; DTR control; write register 6 (used for synchronous mode only);   "	   "	 7 (  "	  "	"	  "	" )	.LOC	ROMM	START:	IOF	IM2	JUMP MAIN	.LOC	IVTAB; Interrupt service routines address tableCTCIV:	.W	CISR0	.W	CISR1	.W	CISR2	.W	CISR3	.ALIGN	O'20SIOIV:	.W	SBISR1	.W	SBISR2	.W	SBISR3	.W	SBISR4	.W	SAISR1	.W	SAISR2	.W	SAISR3	.W	SAISR4; Interrupt service routines for SIO; SIO: registre de sortie vide.; Aprs l'envoi d'un caractre le SIO gnre; continuellement des interrupts jusqu'; l'criture d'un nouveau caractre dans le; registre de sortie (SIBD). Lorsque le der-; nier caractre  t envoy il faut reseter; l'interrupt dans le registre #0 du SIO.SBISR1:	PUSH	AF;	LOAD	A,...;	LOAD	$SIBD,A		; nouveau data	LOAD	A,#RSTBMT	LOAD	$SIBC,A	POP	AF	ION	RETISBISR2:	NOP	ION	RETI; SIO: un caractre reu.SBISR3:	EX	AF	EX	BL	LOAD	HL,HEAD		; HL <-- ^tte	LOAD	A,TAIL		; A  <-- ^queue (low byte)	DEC	A	COMP	A,L		; fifo plein ?	JUMP,EQ	80$		; oui => 80$				; non =>	LOAD	A,$SIBD		; A  <-- lit le SIO	LOAD	(HL),A		; met le byte dans le fifo	INC	L		; avance le ^tte	LOAD	HEAD,HL		; met  jour le ^tte	EX	BL	EX	AF	ION	RETI80$:	LOAD	A,$SIBD		; A  <-- lit le SIO pour des prunes !	EX	BL	EX	AF	ION	RETI; SIO: erreur dtecte.SBISR4:	PUSH	AF	LOAD	A,$SIBD		; A <-- lit le SIO;;?	LOAD	A,#R1;;?	LOAD	$SIBC,A;;?	LOAD	A,$SIBC;;?	LOAD	$LED,A	LOAD	A,#R0	LOAD	$SIBC,A	LOAD	A,#RSEROR	; clear l'erreur	LOAD	$SIBC,A	POP	AF	ION	RETISAISR1:SAISR2:SAISR3:SAISR4:	NOP	ION	RETICISR0:	NOP	ION	RETICISR1:	NOP	ION	RETI; CTC: interrupt priodique de surveillance.CISR2:	EX	AF	EX	BL	PUSH	IX	LOAD	IX,#TAUSE	LOAD	DE,#LG	LOAD	C,#810$:	LOAD	A,(IX)+OETAT	; A  <-- tat du gnrateur	OR	A,A		; gnrateur libre ?	JUMP,EQ 30$		; oui => 30$	COMP	A,#3		; gnrateur inexistant ?	JUMP,EQ 30$		; oui => 30$				; non =>	LOAD	B,#ENDATT	COMP	A,#1	JUMP,EQ 15$	LOAD	B,#ENDREL15$:	LOAD	L,(IX)+OPENV+0	LOAD	H,(IX)+OPENV+1	; HL <-- ^dans l'enveloppe	LOAD	A,(HL)	COMP	A,B	JUMP,EQ 30$	COMP	A,#ENDREL	JUMP,EQ 30$	INC	HL		; HL <-- avance dans l'enveloppe	LOAD	(IX)+OPENV+0,L	LOAD	(IX)+OPENV+1,H30$:	ADD	IX,DE	DEC	C	JUMP,NE 10$	POP	IX	EX	BL	EX	AF	ION	RETICISR3:	NOP	ION	RETIINIT:	LOAD	A,#IVTAB/O'400	LOAD	I,A		; load high IV	LOAD	HL,#CTAB0	CALL	EXCIT		; init CTC	LOAD	A,#-1	LOAD	$PIAD,A		; all bits to 1	LOAD	HL,#PTAB0	CALL	EXCIT		; init PIO	LOAD	HL,#STAB0	CALL	EXCIT		; init SIO	ION	RETI; Table d'initialisation du CTC; Initialise le CTC canal 0 pour vecteur d'interrupt; et canal 2 pour baudrate ; Quarz 3.6864Mhz 2400=1536 -> prescaler*SIO=16*16, diviseur=6CTAB0:	.B	CTC0,1	.B	CTCIV&O'370	.B	CTC2,2	.B	CINTEN!CTMD!CNSLP!CP016!CLDCS!CRSET	.B	255.	.B	0; Table d'initialisation des PIOPTAB0:	.B      PIAD,1	.B	-1	.B	PIAC,3	.B	PCTRMD,0,PINTDS	; all outputs	.B   	PIBD,1	.B	0	.B	PIBC,3	.B	PCTRMD,0,PINTDS	; all inputs	.B	PPIAC,3	.B	PCTRMD,-1,PINTDS ; all outputs	.B	PPIBD,1	.B	O'252	.B	PPIBC,3	.B	PCTRMD,0,PINTDS	; all inputs	.B	0; Table d'initialisation du SIO; Baudrate= 4Mhz/31250=128/div 8=16 -> X16STAB0:	.B	SIBC,20$-10$10$:	.B	R0,RSCHL	.B	R2,SIOIV&O'376	.B	R1,STAVEC!RCVIM2!TRSIE	.B	R4,X16!SB1		; No parity	.B	R3,RX8B!RCVEN;;?	.B	R5,TX8B!TRSEN20$:	.B	0; Execute a peripheral instruction table; in	HL	^table; out	-; mod	AF, BC, HLEXCIT:	PUSH	BC10$:	LOAD	C,(HL)		; per.adr.	INC	HL	LOAD	B,(HL)		; # of I/O	INC	HL		; HL -> first I/O	OUTIR	LOAD	A,(HL)	OR	A,A		; last per?	JUMP,NE 10$		; no	POP	BC	RETMAIN:	LOAD	SP,#STACK	CALL	INIFIFO	CALL	INITAUSE	LOAD	A,#1	LOAD	NPAT0,A	LOAD	A,#0	LOAD	NPAT1,A	LOAD	A,#1	LOAD	NPAT2,A	LOAD	A,#5	LOAD	TEMP01,A	LOAD	A,#5	LOAD	TEMP12,A	CALL	INIT	LOAD	B,#B'11111111	; B  <-- toutes les cartes	LOAD	A,#0	CALL	WRITE	LOAD	A,#2	CALL	WRITE		; silence !	LOAD	A,#0	CALL	WRITE	CALL	SHOW		; teste les LEDs	CALL	PRESENT		; B  <-- cartes prsentes	LOAD	A,B	LOAD	CARTE,A	LOAD	$LED,A		; montre les cartes prsentes	CALL	DELBIG		; attend ...	LOAD	A,$CONTROL	AND	A,#H'0F	LOAD	CANAL,A	LOAD	$LED,A		; montre le canal MIDI	CALL	DELBIG		; attend ...	XOR	A,A	LOAD	$LED,A		; teint les LEDs	CALL	BADTAUSE	; TAUSE <-- supprime cartes absentesLOOP:	CALL	SCRUTE		; commande les amplitudes	CALL	RDFIFO		; A  <-- lit le fifo	JUMP,CC LOOPNEXT:	LOAD	B,A	LOAD	A,CANAL	LOAD	C,A	LOAD	A,B	OR	A,A	JUMP,SC LOOP		; si pas une commande => LOOP	AND	A,#H'0F	COMP	A,C		; reu sur le bon canal ?	JUMP,NE LOOP	LOAD	A,B	AND	A,#H'F0	COMP	A,#H'90	JUMP,EQ DONOTE	COMP	A,#H'C0	JUMP,EQ DOPROGRAM	JUMP	LOOPDONOTE:10$:	CALL	RDFIFO	JUMP,CC 10$DONOTE1:	LOAD	D,A		; D  <-- numro de la note20$:	CALL	RDFIFO	JUMP,CC 20$	OR	A,A	JUMP,EQ 50$	LOAD	E,A		; E  <-- force de frappe	CALL	FREE		; IX <-- ^gnrateur libre	JUMP,CS DONNOTE	IOF	LOAD	(IX)+OETAT,#1	; tat <-- touche presse	LOAD	A,D	LOAD	(IX)+ONOTE,A	LOAD	HL,#ENV	LOAD	(IX)+OPENV+0,L	LOAD	(IX)+OPENV+1,H	ION	LOAD	B,(IX)+OSEL	; B  <-- carte concerne	LOAD	A,$LED	OR	A,B	LOAD	$LED,A		; allume une LED	XOR	A,A	CALL	WRITE	LOAD	A,#1	CALL	WRITE		; joue la note	LOAD	A,D	CALL	WRITE	XOR	A,A	CALL	WRITE	LOAD	A,#5	CALL	WRITE		; utilise la patterne d'attaque	LOAD	A,NPAT0	CALL	WRITE	XOR	A,A	CALL	WRITE	LOAD	A,#6	CALL	WRITE		; glisse  la patterne suivante	LOAD	A,NPAT1	CALL	WRITE	LOAD	A,TEMP01	CALL	WRITE	JUMP	DONNOTE50$:	LOAD	A,D	CALL	SEARCH		; IX <-- ^gnrateur utilis	JUMP,CS LOOP	LOAD	(IX)+OETAT,#2	; tat <-- touche relche	LOAD	B,(IX)+OSEL	; B  <-- carte concerne	XOR	A,A	CALL	WRITE	LOAD	A,#6	CALL	WRITE		; glisse  la patterne suivante	LOAD	A,NPAT2	CALL	WRITE	LOAD	A,TEMP12	CALL	WRITEDONNOTE:10$:	CALL	SCRUTE		; commande les amplitudes	CALL	RDFIFO		; A  <-- lit le fifo	JUMP,CC 10$	OR	A,A	JUMP,SC DONOTE1	JUMP	NEXTDOPROGRAM:10$:	CALL	RDFIFO	JUMP,CC 10$	LOAD	NPAT0,A	JUMP	LOOP;-------\\; SCRUTE >;=======/; Scrute TAUSE et donne ventuellement des commandes d'amplitude; pour les enveloppes.; in	-; out	-; mod	-SCRUTE:	PUSH	AF	PUSH	BC	PUSH	DE	PUSH	HL	PUSH	IX	LOAD	IX,#TAUSE	LOAD	DE,#LG	LOAD	C,#810$:	LOAD	A,(IX)+OETAT	; A  <-- tat du gnrateur	OR	A,A		; gnrateur libre ?	JUMP,EQ 80$		; oui => 80$				; non =>	LOAD	L,(IX)+OPENV+0	LOAD	H,(IX)+OPENV+1	; HL <-- ^dans l'enveloppe	LOAD	A,(HL)	COMP	A,#ENDATT	; fin de l'attaque ?	JUMP,EQ 80$		; oui => 80$	COMP	A,#ENDREL	; fini n-i-ni ?	JUMP,EQ 50$		; oui => 50$				; non =>	COMP	A,(IX)+OAMPL	; nouvelle amplitude ?	JUMP,EQ 80$		; non => 80$	LOAD	(IX)+OAMPL,A	; oui => mm. nouvelle amplitude	LOAD	B,(IX)+OSEL	; B  <-- carte concerne	LOAD	H,A	XOR	A,A	CALL	WRITE	LOAD	A,#2	CALL	WRITE		; donne nouvelle amplitude	LOAD	A,H	CALL	WRITE	JUMP	80$50$:	LOAD	(IX)+OAMPL,#0	LOAD	B,(IX)+OSEL	; B  <-- carte concerne	XOR	A,A	CALL	WRITE	LOAD	A,#2	CALL	WRITE		; silence	XOR	A,A	CALL	WRITE	LOAD	(IX)+OETAT,#0	; tat <-- "libre"	LOAD	A,B	CPL	A	LOAD	B,A	LOAD	A,$LED	AND	A,B	LOAD	$LED,A		; teint une LED80$:	ADD	IX,DE	DEC	C	JUMP,NE 10$	POP	IX	POP	HL	POP	DE	POP	BC	POP	AF	RET;---------\\; INITAUSE >;=========/; Initialise la table des gnrateurs.; in	-; out	-; mod	-INITAUSE:	PUSH	AF	PUSH	BC	PUSH	DE	PUSH	IX	LOAD	IX,#TAUSE	LOAD	DE,#LG	LOAD	B,#B'00000001	XOR	A,A10$:	LOAD	(IX)+OETAT,A	LOAD	(IX)+OAMPL,A	LOAD	(IX)+OSEL,B	ADD	IX,DE	RLC	B	JUMP,CC 10$	POP	IX	POP	DE	POP	BC	POP	AF	RET;---------\\; BADTAUSE >;=========/; Supprime les gnrateurs inexistants de la table; des gnrateurs.; in	-; out	-; mod	-BADTAUSE:	PUSH	AF	PUSH	BC	PUSH	DE	PUSH	IX	LOAD	IX,#TAUSE	LOAD	DE,#LG	LOAD	B,#8	LOAD	A,CARTE	LOAD	C,A		; C  <-- cartes prsentes10$:	LOAD	A,(IX)+OSEL	AND	A,C	JUMP,NE 50$	LOAD	(IX)+OETAT,#3	; tat <-- "inexistant"50$:	ADD	IX,DE	DECJ,NE	B,10$	POP	IX	POP	DE	POP	BC	POP	AF	RET;--------\\; FREE    >;========/; Cherche un gnrateur libre.; in	-; out	IX	^gnrateur;	CS	erreur; mod	AF, IXFREE:	PUSH	BC	PUSH	DE	LOAD	IX,#TAUSE	LOAD	DE,#LG	LOAD	B,#810$:	LOAD	A,(IX)+OETAT	; A  <-- tat du gnrateur	OR	A,A		; gnrateur libre ?	JUMP,EQ 90$		; oui => 90$	ADD	IX,DE	DECJ,NE	B,10$	LOAD	IX,#TAUSE	LOAD	DE,#LG	LOAD	B,#820$:	LOAD	A,(IX)+OETAT	; A  <-- tat du gnrateur	COMP	A,#2		; gnrateur en "touche relche" ?	JUMP,EQ 90$		; oui => 90$	ADD	IX,DE	DECJ,NE	B,20$	SETC90$:	POP	DE	POP	BC	RET;--------\\; SEARCH  >;========/; Cherche un gnrateur.; in	A	note cherche; out	IX	^gnrateur;	CS	erreur; mod	AF, IXSEARCH:	PUSH	BC	PUSH	DE	LOAD	IX,#TAUSE	LOAD	DE,#LG	LOAD	B,#8	LOAD	C,A10$:	LOAD	A,(IX)+OETAT	; A  <-- tat du gnrateur	COMP	A,#1		; gnrateur occup en "touche presse" ?	JUMP,NE 50$		; non => 50$				; oui =>	LOAD	A,(IX)+ONOTE	COMP	A,C		; est-ce la bonne note ?	JUMP,EQ 90$		; oui => 90$50$:	ADD	IX,DE	DECJ,NE	B,10$	SETC90$:	POP	DE	POP	BC	RET;--------\\; SHOW    >;========/; Vrifie l'tat de toutes les LEDs.; in	-; out	-; mod	-SHOW:	PUSH	AF	PUSH	BC	LOAD	A,#B'0000000110$:	LOAD	$LED,A	CALL	DEL	RLC	A	JUMP,CC 10$	LOAD	$LED,A	POP	BC	POP	AF	RET;--------\\; DELBIG  >;========/; Attend un gros peu ...; in	-; out	-; mod	-DELBIG:	PUSH	AF	PUSH	BC	LOAD	B,#1210$:	CALL	DEL		; attend ...	DECJ,NE	B,10$	POP	BC	POP	AF	RET;--------\\; DEL     >;========/; Attend un p'tit peu ...; in	-; out	-; mod	-DEL:	PUSH	AF	PUSH	BC	LOAD	BC,#1000010$:	DEC	BC	LOAD	A,B	OR	A,C	JUMP,NE	10$	POP	BC	POP	AF	RET;--------\\; PRESENT >;========/; Vrifie quelles sont les cartes prsentes, en; utilisant la ligne "je suis l".; in	-; out	B	cartes prsentes; mod	BCPRESENT:	PUSH	AF	IOF	LOAD	B,#B'00000001	LOAD	C,#010$:	XOR	A,A	CALL	WRITE	LOAD	A,#9	CALL	WRITE	XOR	A,A20$:	DEC	A		; attend un peu ...	JUMP,NE 20$	LOAD	A,$CONTROL	TEST	A:BJSL		; rponse "je suis l" ?	JUMP,NE 50$		; non => 50$30$:	LOAD	A,$CONTROL	TEST	A:BJSL		; attend la fin de la rponse ...	JUMP,EQ 30$	LOAD	A,C	OR	A,B		; C <-- cartes prsentes	LOAD	C,A50$:	RLC	B	JUMP,CC 10$	LOAD	B,C	ION	POP	AF	RET;--------\\; WRITE   >;========/; Envoie un byte  une ou plusieurs cartes.; in	A	data  crire;	B	carte(s) concerne(s); out	-; mod	-WRITE:	PUSH	AF	PUSH	BC	LOAD	C,A10$:	LOAD	A,$CONTROL	TEST	A:BRDY		; toutes les cartes ready ?	JUMP,NE	10$		; non => 10$	LOAD	A,C	LOAD	$DATA,A		; crit le data	LOAD	A,B	CPL	A	LOAD	$SELECT,A	; fait le flan descendant	LOAD	A,#-1	LOAD	$SELECT,A	; fait le flan montant	POP	BC	POP	AF	RET;--------\\; INIFIFO >;========/; Vide compltement le fifo.; in	-; out	-; mod	HLINIFIFO:	IOF	LOAD	HL,#FIFO	; HL <-- ^dbut du fifo	LOAD	HEAD,HL		; init ^tte	LOAD	TAIL,HL		; init ^queue	ION	RET;-------\\; RDFIFO >;=======/; Lit un caractre du fifo. Si celui-ci est vide, revient CC; et ne lit rien.; ATTENTION: pour tre plus rapide, la condition CC/CS est; inverse par rapport  la logique standard (CS=ok) !; in	-; out	CS	ok;	 A	byte lu;	CC	fifo vide;	 A	n'importe quoi; mod	AF,HLRDFIFO:	IOF			; trs important ...	LOAD	HL,TAIL		; HL <-- ^queue	LOAD	A,HEAD		; A  <-- ^tte (low byte)	COMP	A,L		; ^tte = ^queue ?	JUMP.,EQ 90$		; oui => retour CC	LOAD	A,(HL)		; A  <-- byte lu	INC	L		; avance le ^queue	LOAD	TAIL,HL		; met  jour le ^queue	SETC			; retour CS90$:	ION	RETENV:	.B	0,4,8,12,16,20,24,28,32,36,40,44,48,52,56,60,63	.B	ENDATT	.B	63,62,61,60	.B	59,59,59,59,58,58,58,58,57,57,57,57,56,56,56,56,55,55,55,55	.B	54,54,54,54,53,53,53,53,52,52,52,52,51,51,51,51,50,50,50,50	.B	49,49,49,49,48,48,48,48,47,47,47,47,46,46,46,46,45,45,45,45	.B	44,44,44,44,43,43,43,43,42,42,42,42,41,41,41,41,40,40,40,40	.B	39,39,39,39,38,38,38,38,37,37,37,37,36,36,36,36,35,35,35,35	.B	34,34,34,34,33,33,33,33,32,32,32,32,31,31,31,31,30,30,30,30	.B	29,29,29,29,28,28,28,28,27,27,27,27,26,26,26,26,25,25,25,25	.B	24,24,24,24,23,23,23,23,22,22,22,22,21,21,21,21,20,20,20,20	.B	19,19,19,19,18,18,18,18,17,17,17,17,16,16,16,16,15,15,15,15	.B	14,14,14,14,13,13,13,13,12,12,12,12,11,11,11,11,10,10,10,10	.B	09,09,09,09,08,08,08,08,07,07,07,07,06,06,06,06,05,05,05,05	.B	04,04,04,04,03,03,03,03,02,02,02,02,01,01,01,01,00	.B	ENDREL	.END	START